// Source posts: { account, callId, transcript, source, callDate }
const b = $json.body || $json;
const account = b.account || 'UNKNOWN';
const callId = b.callId || ('call_' + Date.now());
const transcript = b.transcript || '';
const source = b.source || 'unknown';
const callDate = b.callDate || new Date().toISOString();
const dedupKey = `${source}:${account}:${callId}`;
return [{ json: { account, callId, transcript, source, callDate, dedupKey } }];

