// Freshness check: enrich if missing OR stale (>24h since last_verified)
const row = $input.first().json || {};
const account = $('Normalize + Dedup').item.json.account;
const exists = !!row.id;
let stale = true;
if (exists && row.last_verified) {
  const ageMs = Date.now() - new Date(row.last_verified).getTime();
  stale = ageMs > 24 * 60 * 60 * 1000;
}
const needsEnrichment = !exists || stale;
return [{ json: { ...row, account, needsEnrichment } }];

// FAIL-SAFE merge: only include sources that returned data; never wipe with empties
const account = $('Assess Freshness').item.json.account;
const safe = (name) => { try { const v = $(name).item.json; return (v && !v.error) ? v : null; } catch (e) { return null; } };
const context = {
  account,
  monday: safe('Get Monday.com'),
  sharepoint: safe('Get SharePoint'),
  org: safe('Get Org & SOW')
};
return [{ json: { account, context } }];

// Assemble the USER message (system message lives on the AI Agent node)
const account = $('Normalize + Dedup').item.json.account;
const transcript = $('Normalize + Dedup').item.json.transcript;
let callId = null; try { callId = $('Store Call').item.json.id; } catch (e) {}
let ctxRow = {}; try { ctxRow = $('Get Account Context').first().json || {}; } catch (e) {}
const summary = ctxRow.feedback_summary || 'None yet.';
const fbRows = $('Get Feedback (by account)').all().map(i => i.json).filter(r => r && r.verdict);
const fbText = fbRows.length ? fbRows.map(f => `- was '${f.verdict}', correct '${f.correct_type || ''}': ${f.reason || ''}`).join('
') : 'None.';
const context = ctxRow.context ? JSON.stringify(ctxRow.context) : 'No stored context.';
const userMessage = `Account: ${account}

Known context:
${context}

Feedback summary for this account:
${summary}

Recent corrections:
${fbText}

Transcript:
${transcript}`;
return [{ json: { account, callId, userMessage } }];

// Parse the agent output, validate, set status by confidence floor
const out = ($input.first().json.output ?? '').toString().trim();
const cleaned = out.replace(/^```json/i, '').replace(/^```/, '').replace(/```$/, '').trim();
let parsed;
try { parsed = JSON.parse(cleaned); } catch (e) { throw new Error('Model did not return valid JSON: ' + out.slice(0, 200)); }
const allowed = ['risk', 'opportunity', 'update', 'people'];
const account = $('Build Agent Input').item.json.account;
const callId = $('Build Agent Input').item.json.callId;
const signals = (parsed.signals || [])
  .filter(s => allowed.includes(s.type))
  .map(s => ({ ...s, account, callId, status: Number(s.confidence) >= 0.6 ? 'new' : 'review' }));
if (!signals.length) return [{ json: { account, callId, note: 'no material signals' } }];
return signals.map(s => ({ json: s }));

