=-- success: mark processed + log
UPDATE inbox SET status = 'done' WHERE dedup_key = '{{ $('Normalize + Dedup').item.json.dedupKey }}';
INSERT INTO run_logs (kind, ref, ok, created_at) VALUES ('main_pipeline', '{{ $('Normalize + Dedup').item.json.dedupKey }}', true, now());

=-- failure: mark failed so it can be retried, never lost
UPDATE inbox SET status = 'failed', attempts = COALESCE(attempts,0) + 1 WHERE dedup_key = '{{ $('Normalize + Dedup').item.json.dedupKey }}';
INSERT INTO run_logs (kind, ref, ok, created_at) VALUES ('main_pipeline', '{{ $('Normalize + Dedup').item.json.dedupKey }}', false, now());
